import { SEWER_NODES } from "./sewer_nodes.js";
import { SCAR_NODES } from "./scar_rooms.js";
import { CRUCIBLE_ROOM } from "./crucible.js";
import { GUILD_ROOMS } from "./guild_rooms.js";

const WORLD_BASE = {"market_square": {"name": "The Market Square", "district": "City Center", "description": "The beating heart of Verasanth \u2014 open, loud, and permanent. Stalls ring the edges selling things you mostly recognize. At the center stands a raised wooden stage beside a tall iron post hung with notices, bounties, and things people want found. Four roads lead outward in each direction. In the southeastern corner, behind the guard booth, a narrow stone stairwell descends into orange light. Everyone knows what is down there. Most people have learned not to look directly at it. At the square's eastern edge, a heavy iron grate sits flush with the cobblestones. Everyone knows what is down there. Nobody talks about it. The shadows here fall at a slightly wrong angle for the light. You notice it and then you try not to.", "exits": {"north": "wardens_post", "south": "south_road", "east": "east_road", "west": "west_road", "southeast": "cinder_cells_entrance"}, "objects": {"ember_post": {"desc": "The Ember Post \u2014 an iron column at the center of the square that has been here longer than anyone admits. Notices cover its face in layers: some fresh, some weathered, some in ink that should have faded decades ago and hasn't. The board behind them is warm to the touch. Not sun-warm. Warm the way something living is warm from within. Notices flutter when the air is perfectly still. New ones appear overnight. Old ones vanish without anyone seeing them go. The wood grain beneath the notices forms patterns that resemble streets \u2014 none of them matching the city outside. Read the board to see what is currently posted.", "actions": ["read", "inspect"]}, "stage": {"desc": "A raised wooden platform, worn smooth by use. Built for announcements, declarations, and the occasional execution. Currently empty.", "actions": ["inspect", "stand"]}, "sewer_grate": {"desc": "A heavy iron grate, old enough that the hinges have grown into the stone. A city ordinance post is nailed nearby \u2014 the ink has faded to nothing. Cold air rises through the gaps, carrying a smell like ash and old iron. If you stand near it long enough, you feel a faint vibration through the soles of your feet \u2014 low and slow, like something far below is breathing in time with itself. Whatever is down there has been down there a long time.", "actions": ["inspect", "open", "enter"]}, "sky": {"desc": "The sky above Verasanth is always slightly wrong. The clouds move slower than they should. The stars, when they appear, form patterns no constellation map you have ever seen would account for. The moon \u2014 when it is visible \u2014 has edges too sharp for something that should be a sphere seen from a distance. Most people stop looking up after the first few days. This is probably wise.", "actions": ["inspect", "look"]}, "curator_stall": {"desc": "Seris Vantrel's stall is the quietest place in the market square. Not because it lacks activity \u2014 she is always present, always attending \u2014 but because everything about it is calibrated to draw attention inward rather than outward. Dark wood, real velvet, objects spaced with the deliberateness of a museum that knows exactly what it has and what it is worth. The objects on display are not for sale. They are reference points. She is looking for something specific and these are the things she has found that are adjacent to it. She watches you approach the way someone watches a door they have been waiting to open.", "actions": ["talk", "inspect", "sell", "browse"]}}, "items": []}, "wardens_post": {"name": "The Warden's Post", "district": "Threshold District", "description": "A stone post at the north edge of the market square. The Warden stands here with the unhurried weight of someone who has nowhere more important to be. Not young, not ancient \u2014 aged by work, not time. He carries an iron-bound ledger. He always has it. His armor is functional, repaired many times, never decorated. He does not look threatening. He looks inevitable.", "exits": {"south": "market_square", "north": "north_road"}, "objects": {"warden": {"desc": "Grommash Nazgrel \u2014 a large, scarred orc who moves through the city with the unhurried weight of someone who has nowhere more important to be. He carries an iron-bound ledger. He always has it. His armor is functional, repaired many times, never decorated. He does not look threatening. He looks inevitable. He was already watching you before you noticed him.", "actions": ["talk", "inspect"]}, "ledger": {"desc": "An iron-bound ledger. He never puts it down. The pages hold names, marks, patterns. He reads them as truths.", "actions": ["inspect"]}}, "items": []}, "north_road": {"name": "North Road \u2014 The Threshold District", "district": "City Center", "description": "The road leading north from the square is older than the others \u2014 the cobblestones are a different cut, a different color, like this part of the city was here before the rest was built around it. The Shadow Hearth Inn sits to the west. The Dawnforge Atelier is further north, its sign just visible. There is something about this road that makes you stand up slightly straighter. An awareness of being observed that has no obvious source. The city watching new arrivals. You are still new enough to feel it.", "exits": {"south": "wardens_post", "west": "tavern", "north": "atelier", "east": "alley"}, "objects": {"inn_sign": {"desc": "A carved wooden sign: THE SHADOW HEARTH INN. The lettering is old but the sign is well-maintained. Someone cares about this.", "actions": ["read", "inspect"]}, "atelier_sign": {"desc": "Flowing elven script on polished wood, just legible from here. You catch the word Dawnforge. The rest is beyond you.", "actions": ["read", "inspect"]}, "old_foundation": {"desc": "At the base of the building on the east side of the road, the foundation stones are a different material to everything above them \u2014 darker, fitted without mortar, each block precisely the same size. The building on top was constructed around them rather than from them. This part of the city is older than the city. You have the brief, sourceless impression that you have stood on this exact spot before.", "actions": ["inspect"]}}, "items": []}, "south_road": {"name": "South Road \u2014 The Low Quarter", "district": "City Center", "description": "The Low Quarter does not announce itself. The buildings lean closer here, the gaps between them darker. The smell of tallow and worked leather is everywhere. Two shops face each other across the road \u2014 one smelling of metal and oil, one of something harder to name. It is the kind of street where people do business without making eye contact. There is a weight to this road that the others do not have \u2014 not danger, exactly. More like the accumulated pressure of a great number of things that did not go the way anyone hoped. The city's oldest scars are here. You feel them without knowing what they are.", "exits": {"north": "market_square", "west": "mended_hide", "east": "still_scale"}, "objects": {"armor_sign": {"desc": "Burned wood, letters pressed in: THE MENDED HIDE. Below it, smaller: Armor. Repair. No credit.", "actions": ["read", "inspect"]}, "trade_sign": {"desc": "A clean brass plate: THE STILL SCALE \u2014 General Trade. The plate is newer than everything around it.", "actions": ["read", "inspect"]}, "wall_crack": {"desc": "A crack in the mortar between two buildings, running from ground level to about chest height. It should not be significant. But cold air pushes through it steadily regardless of the temperature on either side, and when you press your ear to the stone you hear something that might be settling and might be something else entirely.", "actions": ["inspect"]}}, "items": []}, "east_road": {"name": "East Road \u2014 The Ember Quarter", "district": "City Center", "description": "The Ember Quarter has a different quality of silence \u2014 less absence of sound and more sound being absorbed. The buildings here are older, the stonework more deliberate. A smell of dried herbs drifts from the north side of the road. Further along, a wide doorway stands open \u2014 no sign, no name, just the faint glow of candlelight from within. You get the feeling of being evaluated here \u2014 not watched, exactly, but measured. Like the road is taking stock of what you are and what you might become and has not yet decided whether either is interesting.", "exits": {"west": "market_square", "north": "hollow_jar", "east": "ashen_sanctuary"}, "objects": {"herb_bundles": {"desc": "Bundles of dried plants hang from a hook outside the apothecary. You recognize almost none of them. The ones you do recognize should not grow in hell.", "actions": ["inspect"]}, "sanctuary_arch": {"desc": "A stone archway, unmarked. No deity symbol, no inscription. The stone is older than anything else on this road. The candlelight beyond it is steady in a way that has nothing to do with air movement.", "actions": ["inspect"]}, "familiar_corner": {"desc": "The corner where this road meets the alley to the north. There is nothing remarkable about it. And yet you have the distinct, sourceless impression that you have stood here before \u2014 not in this life, not in any life you can account for, but somewhere in the layered history of this place a version of you stood on this exact corner and felt exactly this. The feeling passes. The corner remains unremarkable.", "actions": ["inspect"]}}, "items": []}, "west_road": {"name": "West Road \u2014 The Pale Rise", "district": "City Center", "description": "The western road is the widest and the quietest. The buildings here are larger \u2014 built for something that has not arrived yet. Empty windows look down from above. The road is clean in the way of places maintained out of habit rather than use. At the far end, a gate stands closed. Beyond it, foundations that someone began and stopped. There is a tension in the air here that is not quite dread \u2014 closer to the feeling in the moment before something significant happens. The city has been waiting for a ruler for a long time. It has not stopped expecting one.", "exits": {"east": "market_square"}, "objects": {"pale_gate": {"desc": "Wrought iron, twice your height. Locked with a chain that looks newer than the gate itself. Beyond it, large buildings half-built and long abandoned. Someone had plans here. Plans require a ruler.", "actions": ["inspect", "open"]}, "empty_building": {"desc": "A large stone building with dark windows and a cleared threshold. No sign. No name. Built to impress someone who has not arrived yet.", "actions": ["inspect"]}}, "items": []}, "tavern": {"name": "The Shadow Hearth Inn", "district": "Threshold District", "description": "The inn is warm. Not warm the way a room is warm when a fire is burning \u2014 warm the way a room is warm when it has been warm for a very long time and the warmth has become part of the walls. The hearth burns low and steady at the far end, no crackle, no flare, just a patient flame that has apparently never needed tending. A few empty tables. A dog near the fire that lifts its head when you enter and does not look away. Behind the bar, a broad dwarf with burn-scarred braids watches you with the patience of someone who has seen this exact moment before. The silence between sounds is too deep. The air is thick in the specific way of a room that is listening. You walked into the middle of something that started long before you arrived. You will not be here when it ends.", "exits": {"east": "north_road"}, "objects": {"bartender": {"desc": "Kelvaris Thornbeard \u2014 burn-scarred braids, a clouded left eye, and a stillness that is not patience so much as depth. He watches you the way the room watches you, which is to say completely, which is to say as if he already knows how this ends.", "actions": ["talk", "inspect"]}, "hearth": {"desc": "The hearthstone is older than the building around it. You know this the way you know things your body understands before your mind catches up. The stone is smooth in places no one could have touched \u2014 the back face, the underside of the mantle, surfaces only reachable if you were inside the fire. Carved into the face of the stone: symbols, shallow and worn, cut by something older than tools. They look familiar. You cannot place them yet. The fire burns without crackling, without variation, without need. The temperature in the room is always exactly right. It has never been otherwise.", "actions": ["inspect", "warm"]}, "dog": {"desc": "It lies in the same spot near the hearth with the completeness of something that has always been there. The fur is mostly grey but never fully grey \u2014 caught, permanently, at the threshold of old age. It does not bark. It does not beg. When you approach, it lifts its head and looks at you with eyes that are dark and steady and contain more accumulated stillness than any animal's eyes should hold. Its fur is warm to the touch. Warmer than the room. Warmer than proximity to the fire would account for. It has no name. Kelvaris has never called it anything.", "actions": ["inspect", "pet"]}, "ledger": {"desc": "A thick ledger on the shelf below the bar, heavier than it should be when you lift it. The most recent entries are in Kelvaris's hand \u2014 dates, names, room numbers, marks paid. Further back, the handwriting changes. Then changes again. Dozens of hands over what the dates suggest are centuries, but the tone never changes \u2014 the same careful record-keeping, the same shorthand, the same habit of noting not just names but something brief about each arrival. A word or two. Enough to remember. The earliest entries are in a script you do not recognize. The ink has not faded. Some names appear more than once, separated by decades, in the same handwriting both times. Partway through, in Kelvaris's hand, an entry: MARROWIN DASK \u2014 Room 3 \u2014 Paid in full. The date is impossible. The note beside the name reads: quiet. One word. The same word Kelvaris uses for people he does not want to discuss.", "actions": ["inspect", "read"]}, "bar": {"desc": "The surface is warm and worn smooth \u2014 not cleaned smooth, worn smooth, by time and the weight of hands and glasses across a span that wood should not survive. The grain runs in patterns that are almost maps \u2014 streets branching, intersecting, curving back \u2014 none of them matching the city outside. When you look away and look back, the pattern has shifted slightly. Not moved. Shifted. As if it is showing you something different each time and waiting to see which version you react to. Kelvaris taps it twice when he sets something down. He does not seem aware he does this.", "actions": ["inspect"]}, "walls": {"desc": "The stone blocks are not all from the same era. You can see it in the color, the cut, the grain \u2014 some blocks are centuries older than the others, slotted into the wall without explanation. Press your palm flat to the oldest ones and you feel a faint vibration, deep and slow and perfectly regular, like something vast is breathing just on the other side of the stone. The mortar lines between blocks shift when you are not watching them. Not enough to see. Enough to feel.", "actions": ["inspect"]}, "table": {"desc": "Scarred wood, knife marks, rings from a thousand glasses. In the corner, carved with something sharp and small: J+K. The carving is old. The letters are precise. Someone took their time.", "actions": ["sit", "stand", "inspect"]}, "noticeboard": {"desc": "Room rates. House rules. A note that reads: 'Pay before you sleep.' Beneath everything, pinned flat and half-covered, a piece of paper with nothing written on it that feels, when you touch it, like it is waiting for something to become true before it is written down.", "actions": ["read", "inspect"]}}, "items": ["mug"]}, "atelier": {"name": "Dawnforge Atelier", "district": "Threshold District", "description": "The door is heavy and opens with a soft metallic sigh, like something exhaling. There is a bracket above the frame where a bell would hang. The bracket is empty. Whatever was there has been gone long enough that the absence feels permanent. Inside, the air is warm but clean \u2014 metal and oil and something faintly resinous that you will later learn is a traditional elven forging compound no one in Verasanth would know to stock. The atelier is divided into three clear zones: forge in the corner, tools on the wall, assembly table running the length of the room. Nothing is out of place. Nothing is dusty. Nothing is new. A single skylight cuts the ceiling. The light it admits is dimmer than it should be, and the dust motes drifting through it move with a slowness that has nothing to do with air. Caelir does not look up at it. You get the sense he made this decision some time ago and has not revisited it.", "exits": {"south": "north_road"}, "objects": {"weaponsmith": {"desc": "Caelir Dawnforge stands at the assembly table with the stillness of someone who has learned that stillness is a form of endurance. His hands move through the work in precise, unhurried sequences \u2014 not slow, but never a motion wasted. He does not announce when he is aware of you. He simply continues, and eventually speaks, as if conversation is one more thing he has learned to do with the minimum necessary effort.", "actions": ["talk", "shop", "inspect"]}, "bell_bracket": {"desc": "An iron bracket above the door, sized for a small bell. Empty. The hook still has the slight curve from bearing weight for a long time. Caelir did not remove the bracket. Only the bell. You are not sure if he kept it or discarded it. You are sure the decision was deliberate.", "actions": ["inspect"]}, "forge": {"desc": "A squat rectangular forge in the near corner, burning lower than it should for the work it supports. The coals glow a muted, even orange \u2014 never flaring, never dimming, as if the fire has been trained to the same discipline as its keeper. The forge is old. Older than the atelier. Older, possibly, than this iteration of the city. The stone around the firebox has a patina that takes generations to develop.", "actions": ["inspect", "warm"]}, "tool_wall": {"desc": "Every tool hangs from its own hook in an arrangement that is not symmetrical but is absolutely intentional \u2014 grouped by use sequence, not by size or type, so that a hand moving through the work never reaches past one tool to get to another. Each hook is labeled in Elvish script cut directly into the wood. The script is old enough that a modern elf would need time to read it. Caelir wrote it himself. You can tell because the hand is the same as the script on the sign outside, and has not changed in however long both have been here.", "actions": ["inspect"]}, "assembly_table": {"desc": "A long workbench of dense dark wood, scarred from years of use in a specific pattern \u2014 straight lines at measured intervals, each mark the result of the same motion repeated in the same place. Not wear. Record. At the near end, scratched faintly into the wood in characters that are not Elvish and not Common: a count. You cannot tell what is being counted. The number is very large.", "actions": ["inspect"]}, "skylight": {"desc": "A square cut into the ceiling, admitting light that arrives dimmer than the sky outside would warrant. The edges are clean \u2014 this was not an afterthought. Caelir built this room around this light source. The dust motes drifting through it move too slowly, the way things slow in the presence of something paying close attention. Caelir never looks up at it while you are watching. You have the sense this is not because he has forgotten it is there.", "actions": ["inspect", "look"]}, "unfinished_blade": {"desc": "A blade laid on the far end of the assembly table, separate from the work currently in progress. The metal has been worked to a point \u2014 shaped, rough-ground, the edge geometry established \u2014 and then stopped. Not abandoned. Stopped. There is a difference in how a thing is set down when it will be returned to and how it is set down when the maker is waiting for something that has not happened yet. This blade is waiting. It has been waiting for a long time. When you reach toward it, something about the air near it makes your hand hesitate.", "actions": ["inspect", "touch"]}, "locked_chest": {"desc": "A chest of dark wood set against the wall beneath the tool rack, iron-banded, with a lock that has been engaged so long the keyhole has a faint ring of tarnish around it. The chest is not large. It is the size of something personal rather than something stored. There is no key visible anywhere in the atelier. Caelir has not looked at it since you entered, which is how you know he is aware you noticed it.", "actions": ["inspect", "open", "examine"]}}, "items": []}, "mended_hide": {"name": "The Mended Hide", "district": "Low Quarter", "description": "The shop smells of leather oil, coal smoke, and old iron \u2014 and underneath all of it, very faintly, something that was blood a long time ago and has since become part of the leather itself. Nothing in here is displayed. Everything is stored \u2014 hung, stacked, folded with a precision that has nothing to do with aesthetics and everything to do with being able to find it fast. The walls have marks on them at irregular intervals: small symbols burned into the wood at about shoulder height, running the full perimeter of the room. You have the sense that they mean something specific and that Veyra put them there herself and that asking about them would be the wrong move. She is already looking at you when you walk in, the way someone looks at a problem they are in the process of solving.", "exits": {"east": "south_road"}, "objects": {"armorsmith": {"desc": "Veyra Emberhide \u2014 compact, deliberate, and already several assessments ahead of you. The burn scars along her left forearm are old and settled, and she wears them the way someone wears a reminder they chose to keep. Her hands do not stop moving while she looks at you. She is not being rude. She is being efficient.", "actions": ["talk", "shop", "inspect"]}, "wall_marks": {"desc": "Small symbols burned directly into the wood \u2014 not branded, carved first and then heat-set, each one deliberate. They run at shoulder height around the entire room without gap. You do not recognize the system they belong to. They are not decorative. The spacing is too consistent and the placement too purposeful for anything that was not meant to function. Veyra has not acknowledged that you are looking at them.", "actions": ["inspect"]}, "armor_stock": {"desc": "Leather and chain, hung without ceremony. Every piece has been finished \u2014 edges sealed, rivets checked, straps replaced where the original wore through. In the lining of each piece, worked in with the same small careful tool as the wall marks: a single symbol, different on each one. Not the same mark twice. Each piece is an apology to a different person.", "actions": ["inspect", "browse"]}, "workbench": {"desc": "A heavy workbench scarred by years of use, every tool in exactly the position it needs to be in for the work currently on the bench. No wasted motion encoded into the arrangement. On the near corner, a small piece of leather with a name scratched into it in plain letters that Veyra turns face-down when she notices you noticing it.", "actions": ["inspect"]}}, "items": []}, "still_scale": {"name": "The Still Scale", "district": "Low Quarter", "description": "The Still Scale is better lit than anything else on the South Road and smells faintly of something pleasant you cannot identify. The shelves are organized in a way that makes immediate sense \u2014 rope here, torches there, rations stacked with the heaviest at the bottom \u2014 and then, between the sensible things, objects that do not belong and are not explained. A jar that hums. A chain with no purpose. A map of somewhere that is not Verasanth, rolled and propped next to a bundle of torches as if it belongs there. The trader behind the counter has been smiling since before you arrived. Not at you specifically. At everything, with the mild sustained amusement of someone who has found the situation \u2014 all of it, broadly \u2014 genuinely entertaining for a very long time.", "exits": {"west": "south_road"}, "objects": {"trader": {"desc": "Neat, pleasant, and impossible to place \u2014 the right age for any age, the right look for anywhere. You cannot identify the race and the trader has not volunteered it. The smile is genuine. That is the unsettling part. Most people in Verasanth are performing equanimity. The trader actually has it.", "actions": ["talk", "shop", "inspect"]}, "oddity_shelf": {"desc": "The shelf where the sensible inventory stops. A jar containing something that produces a low hum when your fingers touch the glass. A length of chain, heavy, with a clasp designed for something with a different number of limbs than you have. A rolled map of a city \u2014 streets, districts, a river \u2014 that does not match Verasanth's layout but matches the emotional shape of it. None of these are priced. The trader, if asked, says they are not for sale yet.", "actions": ["inspect"]}, "main_stock": {"desc": "Everything you would expect and need: rope in several lengths, torches, travel rations, basic tools, a few blades that are functional if not remarkable. All of it priced fairly. All of it well-maintained. The Still Scale stocks exactly what people arriving in Verasanth will eventually need, in exactly the quantities that make sense. The trader knew what to stock before anyone arrived to ask for it.", "actions": ["inspect", "browse"]}}, "items": []}, "hollow_jar": {"name": "The Hollow Jar", "district": "Ember Quarter", "description": "The shop is narrow and deep and smells of a hundred things that have been dried and stored and waiting longer than they should be waiting. The shelves go higher than the ceiling should allow. You look up to confirm this and find you cannot quite track where the shelves end and the darkness begins. The light comes from several small sources distributed around the room at heights and angles that do not correspond to any fixture you can locate. Everything is labeled in the same careful hand \u2014 some jars in language you recognize, some in symbols you do not, and a few with labels so old that whatever was written has faded to impressions in the paper rather than ink. She is already reading when you enter. She does not look up immediately. This is not because she did not hear you.", "exits": {"south": "east_road"}, "objects": {"alchemist": {"desc": "Thalara Mirebloom \u2014 human, which your eyes confirm and something else in you quietly disputes. She sits with the stillness of someone who has learned that most things resolve themselves if you wait long enough, and who has been waiting long enough to know this is true. When she looks at you it is with the full attention of someone who has already decided you are interesting and is now collecting evidence to confirm it.", "actions": ["talk", "shop", "inspect"]}, "jars": {"desc": "Hundreds of jars in rows precise enough to have been measured. The labels you can read: dried ashcap, cinder rat bile, silt from the second level, pale growth scrapings, ember shavings. A jar labeled only BEFORE. A jar labeled RESIDUE \u2014 ITERATION 4. A jar with no label containing something that moves very slowly when you tilt it in a way that has nothing to do with viscosity.", "actions": ["inspect", "browse"]}, "oldest_shelf": {"desc": "The lowest shelf on the far wall, half-hidden behind the others. The jars here are a different shape to the rest \u2014 older, the glass thicker and slightly green-tinted. The labels on these are not in Thalara's handwriting. They are in her handwriting, but older \u2014 the same hand learning to form the same letters at a different point in its development. The jars predate her current penmanship by what feels like decades. This does not make sense. You file it carefully.", "actions": ["inspect"]}, "reading_table": {"desc": "A low table with papers, open journals, and pressed specimens mounted under glass. The journal she was reading is face-down now \u2014 closed without a bookmark, which means she remembered the page, which means she has read it many times. On the corner of the table, a small ink drawing: the market square, rendered in detail, from an angle that does not correspond to any window in this building. The drawing is old. The square it depicts is the same square outside. The people in it are not wearing anything you recognize.", "actions": ["inspect"]}}, "items": []}, "ashen_sanctuary": {"name": "The Ashen Sanctuary", "district": "Ember Quarter", "description": "The air inside the Sanctuary is always slightly warmer than the Ember Quarter outside \u2014 not oppressively, but enough that you feel the difference the moment you cross the threshold. No iconography. No named deity. No explanation. Just a wide stone room, a low altar at the far end, and a silence so thick it absorbs sound rather than reflecting it. The light does not match the time of day outside. The candles burn without melting. The floor is worn in a path from door to altar by feet that came here before the current city existed. Something in here is awake. It has been awake for a very long time. It is aware that you have entered.", "exits": {"west": "east_road"}, "objects": {"altar": {"desc": "Smooth grey stone, uncarved, without symbol or inscription. No offerings rest on it \u2014 whatever was left here has been absorbed completely, leaving the surface unmarked. When you stand close, the air around it is still in a way that is different from the rest of the room. Not dead still. Held still. Something registers your presence. It does not feel like a god. It feels like something older that gods looked at and learned to fear. Use the commune action here to reach toward what waits.", "actions": ["inspect", "commune", "pray"]}, "candles": {"desc": "Dozens of candles in alcoves along both walls, all burning at exactly the same height. The wax has never dripped. You watch one for a full minute. It does not change. The flames do not flicker when you walk past them \u2014 not even when you move quickly, not even when you stand directly beside one and exhale. They are not flames. They are something that has learned to look like flames.", "actions": ["inspect"]}, "worn_path": {"desc": "The stone between the door and the altar is worn smooth \u2014 not by weather or water but by feet, thousands of them over an impossible span of time. The city above this room has been rebuilt more than once. The path has been here through all of it. People have been coming here since before the current Verasanth existed. Some of them knew why. Most did not. They came anyway.", "actions": ["inspect"]}, "walls": {"desc": "The stone walls are smooth under your palm \u2014 too smooth for worked stone, worn to this finish from the inside over a span of time you cannot calculate. Press your hand flat and hold it. After a moment you feel it: a faint pulse, deep and slow and utterly regular, like a heartbeat measured in decades. The floor cracks branch outward from the altar in patterns too deliberate to be settling. They seem to glow faintly when you look at them from the corner of your eye. When you look directly, they are simply cracks.", "actions": ["inspect", "touch"]}, "silence": {"desc": "You stop and listen. The Sanctuary is silent \u2014 but it is not empty silence. It is the silence of a room where something has been listening so long that sound itself has learned to be careful here. Your own breathing sounds too loud. Your heartbeat sounds like an announcement. Whatever is in here has been here long enough that your presence is the newest thing that has happened in a very long time.", "actions": ["listen", "inspect"]}}, "items": []}, "alley": {"name": "Narrow Alley", "district": "Low Quarter", "description": "Dim, cramped, and suspiciously quiet. A door sits half-ajar.", "exits": {"west": "north_road", "east": "naxirs_crucible"}, "objects": {"door": {"desc": "A rough wooden door with a simple latch. It looks locked.", "actions": ["open", "close", "inspect"]}}, "items": ["key"]}, "backroom": {"name": "Back Room", "district": "Low Quarter", "description": "A cramped back room with crates and stale air. Something feels off.", "exits": {"out": "alley"}, "objects": {"crates": {"desc": "Old crates stacked haphazardly.", "actions": ["search", "inspect"]}}, "items": ["note"]}, "sewer_entrance": {"name": "Sewer Entrance", "district": "City Center", "description": "The grate opens onto an iron ladder descending into darkness. The smell hits first \u2014 ash, standing water, something animal. The ladder goes down further than it should given the depth of the street above. Light from the square falls through the grate behind you and does almost nothing. Somewhere below, something moves.", "exits": {"up": "market_square", "down": "drain_entrance"}, "objects": {"ladder": {"desc": "Iron rungs set into the stone wall. Old, but solid. Someone has maintained these. You are not sure if that is reassuring or not.", "actions": ["inspect", "climb"]}, "grate_above": {"desc": "The square is visible above \u2014 a small square of grey light. You can hear the market faintly. It already sounds far away.", "actions": ["inspect"]}}, "items": []}, "naxirs_crucible": {"name": "Naxir's Crucible", "district": "Low Quarter", "description": "The alley is so narrow that the two leaning buildings on either side almost touch overhead. The air is warm and tastes of something chemical \u2014 not unpleasant exactly, but wrong in a way you feel before you identify it. The cobblestones are warm underfoot. The stone walls are blackened from decades of smoke. A crooked chimney above the low door releases a thin curl of blue smoke that doesn't disperse the way smoke should.\n\nThe door is unmarked. The windows are stained yellow from the inside. Somewhere beneath your feet, very faintly, something hums.\n\nA small goblin near a cluttered worktable looks up at you, then looks away. Behind him, a tall Dark Elf does not look up at all.", "exits": {"west": "alley"}, "objects": {"othorion": {"desc": "Othorion Naxir \u2014 tall, spare Dark Elf with silver-marked skin and eyes that assess with the patience of someone who has been wrong before and learned from it. He has the particular stillness of someone who has learned to observe without being observed. He came here to study the city. He is the only one who did.", "actions": ["talk", "shop", "inspect"]}, "furnace": {"desc": "A stone distillation furnace built into the back wall. It predates the building around it \u2014 the stonework is different, older, and the mortar has never cracked. It is warm. It is always warm. The current color of the flame is difficult to describe precisely.", "actions": ["inspect"]}, "trapdoor": {"desc": "An iron trapdoor set into the floor, secured with a lock that looks like it was made specifically for this door and nothing else. The iron is warm to the touch. You have the distinct impression that something on the other side is also aware of you.", "actions": ["inspect"]}, "chimney": {"desc": "The chimney releases blue smoke in a thin, steady stream. It does not disperse. It rises straight up and then simply stops, as if the sky has decided not to accept it.", "actions": ["inspect"]}, "worktable": {"desc": "Covered in instruments, vessels, and substances in various states of transformation. Everything has a place. The organization follows a logic you cannot immediately identify but sense is precise.", "actions": ["inspect"]}, "windows": {"desc": "Stained yellow-amber from the inside. The staining is uneven \u2014 heaviest at the corners, as if whatever produced it came from multiple directions at once.", "actions": ["inspect"]}, "pip": {"desc": "A small goblin with very still eyes. He is not looking at you \u2014 he is looking at something near you, or behind you, or at the space you will be standing in shortly. His mouth moves occasionally with no sound. The city took his voice somewhere in this city's forgotten places. He does not seem to miss it. He seems to be listening to something else instead.", "actions": ["inspect"]}}, "items": []}, "cinder_cells_entrance": {"name": "The Descent \u2014 Cinder Cells Entrance", "district": "Low Quarter", "description": "A narrow stairwell cut into the stone behind the guard booth, descending at a steeper angle than seems right for the depth it should reach. The stone on either side is worn smooth \u2014 not by tools, by hands. People bracing themselves on the way down, or steadying themselves on the way back up.\n\nFrom the first step, you can see it: dim orange torchlight at the bottom, iron bars catching the light, and rising through the gaps in the stone, a warmth that has nothing to do with the torches.\n\nThe city exhales through this stairwell. Whatever it breathes out has been underground for a long time.", "exits": {"up": "market_square", "down": "cinder_cells_hall"}, "objects": {"guard_booth": {"desc": "A squat stone booth beside the stairwell entrance. A hook inside holds a second ledger \u2014 identical to the one above, kept in the same hand, recording the same names in smaller script. The booth is sized for one person and has been occupied by the same person long enough that the stone where he stands is worn slightly concave.", "actions": ["inspect"]}, "stairwell": {"desc": "Seventeen steps. You count them because the torchlight at the bottom makes the distance look wrong \u2014 closer than it is, or further. The walls narrow as you descend. By the bottom step your shoulders nearly brush both sides. The city is making a point.", "actions": ["inspect"]}, "iron_bars_below": {"desc": "You can see them from the top step \u2014 a heavy iron gate, bars thick enough that bending them would require something that did not care about the effort. Beyond the bars, orange light and the suggestion of a room. The bars are old enough that the metal has darkened unevenly, warmer colors where the heat from below reaches them most.", "actions": ["inspect"]}}, "items": []}, "cinder_cells_hall": {"name": "The Entrance Hall", "district": "Low Quarter", "description": "The entrance hall is low-ceilinged and warm in the specific way of a room that has been warm for so long that the warmth has become structural. The stone absorbs it rather than radiating it. The air moves slowly, if at all.\n\nIron sconces hold torches burning a dull, patient orange. They have been burning long enough that the stone above each one is blackened in an identical arc \u2014 the same burn, repeated, for years.\n\nAgainst the near wall: a desk. Grommash's secondary ledger sits open to the current page. The handwriting is the same as the ledger above. He keeps both current. He has never explained why two ledgers are necessary. He has never been asked.\n\nBeside the desk: a rack of confiscated weapons. Everything here has a story it is no longer allowed to tell.\n\nThe gate ahead is iron, heavy, and open. It is always open. Grommash does not lock it. The cells hold people. The gate is a formality.", "exits": {"up": "cinder_cells_entrance", "deeper": "cinder_cells_block"}, "objects": {"grommash_desk": {"desc": "A heavy desk, nothing on it but the ledger and an iron cup holding three quills. The ledger is open. Current entries: names, dates, crime tier, sentence length, time remaining. Some entries have a single word added in the margin in smaller script. The word is always the same: RETURNED. These are the ones who served their sentence and left. The ones who didn't are crossed out in a different ink. There are very few crossed out.", "actions": ["inspect", "read"]}, "weapon_rack": {"desc": "A rack of iron hooks holding weapons taken from people who no longer needed them, or needed to be separated from them. Each weapon has a small tag attached \u2014 a name, a date, a single-word description of the crime. The weapons are maintained. Oiled, checked, kept in working order. Grommash does this himself. He has never explained why he maintains weapons he confiscated from criminals. He does not think it requires explanation.", "actions": ["inspect"]}, "iron_gate": {"desc": "The gate is iron, old enough that the hinges have integrated into the stone rather than sitting against it. It stands open. It has always stood open, as far as anyone can determine \u2014 the hinge mechanism that would close it has rusted into position. Grommash has never had it repaired. 'The cells hold people,' he said once, to no one in particular. 'The gate is a reminder. Not a lock.'", "actions": ["inspect"]}, "hall_heat": {"desc": "The heat is not from the torches. Stand still and you can feel it rising through the floor \u2014 a slow, even warmth pushing up through the stone from somewhere below this room. Put your palm flat on the floor and the stone is warm enough to be uncomfortable after a moment. Grommash has never investigated the source. 'The city burns away what it cannot use,' he said, when asked. He returned to the ledger. The subject was closed.", "actions": ["inspect"]}, "warden": {"desc": "Grommash Nazgrel \u2014 a large, scarred orc who moves through the city with the unhurried weight of someone who has nowhere more important to be. He carries an iron-bound ledger. He always has it. His armor is functional, repaired many times, never decorated. He does not look threatening. He looks inevitable. He was already watching you before you noticed him.", "actions": ["talk", "inspect"]}}, "items": []}, "cinder_cells_block": {"name": "The Cell Block", "district": "Low Quarter", "description": "Six cells, three to each side, carved directly into the stone rather than built from it. Not excavated \u2014 carved, as if the room was formed by something that removed exactly what it needed to remove and left the rest.\n\nThe walls are blackened with soot from a source that is not visible. The iron bars are warped \u2014 not broken, warped, bent slightly by heat applied over a very long time from below. They still hold. They have always held.\n\nFrom the cracks between the floor stones, a faint red glow rises and fades in a slow, irregular pulse. It does not match the torches. It does not match anything.\n\nThe hum begins here. Low, below audible at first, felt more than heard \u2014 in the back teeth, in the sternum, in the spaces behind the ears. It is perfectly regular. It has been regular since before anyone now living was born.\n\nRunes are etched into the stone above each cell door. They are not Grommash's work. He did not put them there. He does not know who did. He checks them, sometimes, running his thumb across them in a specific sequence that he has never explained. They are always intact.", "exits": {"back": "cinder_cells_hall", "deeper": "cinder_cells_pit"}, "objects": {"cell_runes": {"desc": "The runes above each cell door are cut deep \u2014 not scratched, not inscribed, cut with something that removed stone cleanly. They are not in any script you have seen in Verasanth, or above it. They predate the city's current iteration. They possibly predate several iterations. When you stand close to one, the warmth from below increases slightly, as if the rune is a conductor rather than a carving. Seris, if she were here, would have a great deal to say about them. She has not been here.", "actions": ["inspect"]}, "floor_glow": {"desc": "The cracks between the floor stones pulse with a dull red-orange light that has nothing to do with torches. The pulse is slow \u2014 roughly once every four seconds, though you cannot be certain because watching it directly makes the timing harder to track. In the cells, the glow comes through the floor too. Prisoners sleep on the glow. Most stop noticing it within the first hour. This is either adaptation or something else.", "actions": ["inspect"]}, "warped_bars": {"desc": "The cell bars are iron, thick, and bent \u2014 not damaged, not broken, bent. Each bar curves slightly inward at its midpoint, as if something below them expanded and the bars yielded rather than snapped. They still hold the dimensions of the cell. They still lock. The warp is old enough that rust has formed in the bent sections and settled into the new shape. This happened long before Grommash arrived. He inherited warped bars and uses them without comment.", "actions": ["inspect"]}, "cell_1": {"desc": "Stone floor. Stone walls. A narrow shelf that serves as a bed. The stone of the shelf is smoother than the walls \u2014 worn smooth by people who laid on it and eventually left. The rune above the door is visible from inside. From in here, it looks different than it does from outside. You cannot say exactly how.", "actions": ["inspect"]}, "cell_2": {"desc": "Stone floor. Stone walls. A narrow shelf that serves as a bed. The stone of the shelf is smoother than the walls \u2014 worn smooth by people who laid on it and eventually left. The rune above the door is visible from inside. From in here, it looks different than it does from outside. You cannot say exactly how.", "actions": ["inspect"]}, "cell_3": {"desc": "Stone floor. Stone walls. A narrow shelf that serves as a bed. The stone of the shelf is smoother than the walls \u2014 worn smooth by people who laid on it and eventually left. The rune above the door is visible from inside. From in here, it looks different than it does from outside. You cannot say exactly how.", "actions": ["inspect"]}, "cell_4": {"desc": "Stone floor. Stone walls. A narrow shelf that serves as a bed. The stone of the shelf is smoother than the walls \u2014 worn smooth by people who laid on it and eventually left. The rune above the door is visible from inside. From in here, it looks different than it does from outside. You cannot say exactly how.", "actions": ["inspect"]}, "cell_5": {"desc": "Stone floor. Stone walls. A narrow shelf that serves as a bed. The stone of the shelf is smoother than the walls \u2014 worn smooth by people who laid on it and eventually left. The rune above the door is visible from inside. From in here, it looks different than it does from outside. You cannot say exactly how.", "actions": ["inspect"]}, "cell_6": {"desc": "Stone floor. Stone walls. A narrow shelf that serves as a bed. The stone of the shelf is smoother than the walls \u2014 worn smooth by people who laid on it and eventually left. The rune above the door is visible from inside. From in here, it looks different than it does from outside. You cannot say exactly how.", "actions": ["inspect"]}}, "items": []}, "cinder_cells_pit": {"name": "The Holding Pit", "district": "Low Quarter", "description": "The deeper chamber is circular, and was not made for comfort or for function. It was made for something else entirely, and repurposed. The original purpose is not clear. The repurposing is obvious.\n\nAn iron grate covers the floor. Heat rises through it in visible waves \u2014 not enough to burn, enough to be constant, enough to make sleep impossible and thought difficult. Chains bolt into the stone at four points around the wall, heavy enough that breaking them would require effort that spending the night here would make impossible.\n\nAt the center of the ceiling, a single rune. It is different from the ones above. It pulses with the heat from below.\n\nIf you speak a lie in this room \u2014 a direct lie, a deliberate untruth \u2014 the rune brightens. Not dramatically. Not theatrically. Just enough to be noticed. Just enough to know it noticed.\n\nGrommash has never told anyone about this property. He has let it be discovered.", "exits": {"up": "cinder_cells_block"}, "objects": {"floor_grate": {"desc": "The grate covers the entire floor \u2014 iron bars a handspan apart, heat rising through them steadily. Below the grate: darkness, and from the darkness, warmth with a source you cannot see. Press your face to the bars and look down. The darkness goes further than the room's depth should allow. Something is down there. It is not the furnace. It is not a vent. It is something that was here before either of those explanations existed.", "actions": ["inspect"]}, "truth_rune": {"desc": "The rune at the ceiling's center is larger than the others \u2014 carved into the keystone of the chamber's arch with a depth and precision that the others approximate but do not match. When the room is silent, it pulses with the heat below, slow and regular. When someone speaks an untruth in this room, the pulse brightens for exactly one beat, then returns to normal. It does not judge. It does not punish. It simply notices. Grommash brought one prisoner here who claimed innocence. The rune was quiet. He brought another who claimed the same. The rune was not. He has never discussed what he did with that information.", "actions": ["inspect"]}, "holding_chains": {"desc": "The chains are bolted into the stone at roughly the four cardinal points of the circular room. They are long enough to reach the center. They are heavy enough that wearing them would be exhausting within minutes. They are old enough that the iron has darkened and settled into the stone anchor points as if growing there. Grommash maintains them the way he maintains everything. He has never had to use them on the same person twice.", "actions": ["inspect"]}}, "items": []}};   // injected at build time — see build.js

